class Model:
    def __init__(self):
        self.items = []
    def add(self, x):
        self.items.append(x)

class Controller:
    def __init__(self, m):
        self.m = m
    def add(self, x):
        self.m.add(x)
        return len(self.m.items)

c = Controller(Model())
print(c.add('a'), c.add('b'))
